const body = msg.payload || {};
const data = body.data || {};
const key = data.key || {};
const event = String(body.event || '').toLowerCase();

// Configure no .env do Node-RED (somente dígitos)
const BOT_NUMBER = String(env.get('BOT_NUMBER') || '555196172712').replace(/\D/g, '');

function onlyDigits(v) {
  return String(v || '').replace(/\D/g, '');
}

function safeContextSegment(v) {
  return String(v || '')
    .trim()
    .replace(/\s+/g, '_')
    .replace(/[^a-zA-Z0-9:_-]/g, '');
}

function isGroupOrStatus(jid) {
  jid = String(jid || '');
  return jid.endsWith('@g.us') || jid === 'status@broadcast' || jid.includes('@newsletter');
}

function isRealWhatsappJid(jid) {
  jid = String(jid || '');
  return jid.endsWith('@s.whatsapp.net') || jid.endsWith('@c.us');
}

function looksLikeLid(jid) {
  return String(jid || '').includes('@lid');
}

if (event !== 'messages.upsert') {
  msg.statusCode = 200;
  msg.payload = { ok: true, ignored: true, reason: 'evento_ignorado', event: body.event || null };
  return [null, msg, null];
}

if (key.fromMe === true) {
  msg.statusCode = 200;
  msg.payload = { ok: true, ignored: true, reason: 'fromMe' };
  return [null, msg, null];
}

const instance = body.instance || body.instanceName || data.instance || data.instanceName || env.get('EVOLUTION_INSTANCE') || 'danielteste';
const pushName = body.pushName || data.pushName || 'Cliente';

const candidates = [
  key.participant,
  data.participant,
  body.senderPn,
  data.senderPn,
  body.sender,
  data.sender,
  key.remoteJid,
  data.remoteJid,
  body.remoteJid,
  key.remoteJidAlt
].filter(Boolean);

const senderCandidates = [
  key.participant,
  data.participant,
  body.senderPn,
  data.senderPn,
  body.sender,
  data.sender
].filter(Boolean);

const chatCandidates = [
  key.remoteJid,
  data.remoteJid,
  body.remoteJid,
  key.remoteJidAlt
].filter(Boolean);

const preferredCandidates = senderCandidates.concat(chatCandidates);
let chosen = preferredCandidates.find(function(j) { return isRealWhatsappJid(j) && !isGroupOrStatus(j) && !looksLikeLid(j); }) || '';

if (!chosen && key.fromMe !== true && BOT_NUMBER) {
  chosen = preferredCandidates.find(function(j) {
    const digits = onlyDigits(j);
    return isRealWhatsappJid(j) && !isGroupOrStatus(j) && !looksLikeLid(j) && digits && digits !== BOT_NUMBER;
  }) || '';
}

if (!chosen) {
  msg.statusCode = 200;
  msg.payload = { ok: true, ignored: true, reason: 'jid_sem_numero_real', instance, candidates, senderCandidates, chatCandidates };
  return [null, msg, null];
}

const number = onlyDigits(chosen);
if (!number) {
  msg.statusCode = 200;
  msg.payload = { ok: true, ignored: true, reason: 'numero_invalido', instance, chosen, candidates, senderCandidates, chatCandidates };
  return [null, msg, null];
}

if (BOT_NUMBER && number === BOT_NUMBER) {
  const nonBotFallback = preferredCandidates.find(function(j) {
    const digits = onlyDigits(j);
    return isRealWhatsappJid(j) && !isGroupOrStatus(j) && !looksLikeLid(j) && digits && digits !== BOT_NUMBER;
  }) || '';

  if (nonBotFallback) {
    chosen = nonBotFallback;
  } else {
    msg.statusCode = 200;
    msg.payload = {
      ok: true,
      ignored: true,
      reason: 'numero_do_proprio_bot',
      instance,
      chosen,
      number,
      botNumber: BOT_NUMBER,
      candidates,
      senderCandidates,
      chatCandidates
    };
    return [null, msg, null];
  }
}

const finalNumber = onlyDigits(chosen);
if (!finalNumber) {
  msg.statusCode = 200;
  msg.payload = { ok: true, ignored: true, reason: 'numero_invalido', instance, chosen, candidates, senderCandidates, chatCandidates };
  return [null, msg, null];
}

let receivedText = '';
if (data.message) {
  const message = data.message || {};
  const extended = message.extendedTextMessage || {};
  const image = message.imageMessage || {};
  const video = message.videoMessage || {};
  const document = message.documentMessage || {};

  receivedText = message.conversation
    || extended.text
    || image.caption
    || video.caption
    || document.caption
    || '';
}
receivedText = String(receivedText || '').trim();

if (!receivedText) {
  msg.statusCode = 200;
  msg.payload = { ok: true, ignored: true, reason: 'mensagem_sem_texto', instance, number: finalNumber };
  return [null, msg, null];
}

const dedupeWindowMs = 15000;
const now = Date.now();
const dedupeStore = flow.get('dedupeStore') || {};
const messageId = key.id || data.id || body.id || '';
const dedupeKey = messageId
  ? instance + ':' + finalNumber + ':msgid:' + messageId
  : instance + ':' + finalNumber + ':text:' + receivedText.toLowerCase();

for (const k in dedupeStore) {
  if (now - dedupeStore[k] > dedupeWindowMs) delete dedupeStore[k];
}

if (dedupeStore[dedupeKey] && (now - dedupeStore[dedupeKey] < dedupeWindowMs)) {
  flow.set('dedupeStore', dedupeStore);
  msg.statusCode = 200;
  msg.payload = { ok: true, ignored: true, reason: 'mensagem_duplicada', instance, number: finalNumber, dedupeKey };
  return [null, msg, null];
}

dedupeStore[dedupeKey] = now;
flow.set('dedupeStore', dedupeStore);

const floodWindowMs = 5000;
const floodStore = flow.get('floodStore') || {};
const floodKey = instance + ':' + finalNumber;
if (floodStore[floodKey] && (now - floodStore[floodKey] < floodWindowMs)) {
  msg.statusCode = 200;
  msg.payload = { ok: true, ignored: true, reason: 'flood_bloqueado', instance, number: finalNumber, floodKey };
  return [null, msg, null];
}

floodStore[floodKey] = now;
flow.set('floodStore', floodStore);

const memoryInstance = safeContextSegment(instance) || 'default';
const memoryNumber = safeContextSegment(finalNumber) || 'unknown';
const memoryKey = 'memory:' + memoryInstance + ':' + memoryNumber;
let history = flow.get(memoryKey) || [];
history = Array.isArray(history) ? history.slice(-10) : [];

msg._meta = {
  event,
  instance,
  pushName,
  chosen,
  number: finalNumber,
  candidates,
  receivedText,
  dedupeKey,
  memoryKey
};
msg._history = history;

return [msg, null, msg];

const history = msg._history || [];
const messages = [
  {
    role: 'system',
    content: 'Você é um atendente profissional no WhatsApp. Responda em português do Brasil, seja claro, educado e objetivo, não invente informações, se faltar contexto peça mais detalhes, não diga que é IA a menos que perguntem e mantenha respostas curtas ou médias.'
  }
];

for (const item of history) {
  if (item && item.role && item.content) {
    messages.push({ role: item.role, content: item.content });
  }
}

messages.push({
  role: 'user',
  content: `Nome do cliente: ${msg._meta.pushName}\nNúmero: ${msg._meta.number}\n\nMensagem atual do cliente:\n${msg._meta.receivedText}`
});

msg.method = 'POST';
msg.url = 'https://api.mistral.ai/v1/chat/completions';
msg.headers = {
  Authorization: 'Bearer ' + env.get('MISTRAL_API_KEY'),
  'Content-Type': 'application/json'
};
msg.payload = {
  model: 'mistral-small-latest',
  messages,
  max_tokens: 300,
  temperature: 0.3
};

return msg;

let aiText = '';
const payload = msg.payload || {};

function hasRateLimitText(v) {
  return /rate\s*limit|too\s*many\s*requests|429|quota/i.test(String(v || ''));
}

function hasProviderError(p) {
  if (!p || typeof p !== 'object') return false;
  const candidates = [
    p.error,
    p.message,
    p.detail,
    p?.error?.message,
    p?.error?.type,
    p?.error?.code
  ];
  return candidates.some(function(item) {
    const text = typeof item === 'string' ? item : JSON.stringify(item || '');
    return /error|invalid|unauthorized|forbidden|rate\s*limit|too\s*many\s*requests|quota|insufficient/i.test(text);
  });
}

if (typeof payload === 'string') {
  aiText = payload;
} else if (payload.choices && payload.choices[0] && payload.choices[0].message && payload.choices[0].message.content) {
  aiText = payload.choices[0].message.content;
} else if (payload.content) {
  aiText = payload.content;
} else if (payload.text) {
  aiText = payload.text;
} else if (payload.message && !hasProviderError(payload)) {
  aiText = payload.message;
}

if (Array.isArray(aiText)) {
  aiText = aiText.map(function(part) {
    if (typeof part === 'string') return part;
    if (part && part.text) return part.text;
    return '';
  }).join(' ');
}

aiText = String(aiText || '').trim();

const providerError = hasProviderError(payload) || hasRateLimitText(aiText);
if (!aiText || providerError) {
  aiText = 'Recebi sua mensagem 👍 Estou finalizando um atendimento aqui e já te respondo melhor.';
}

const memoryKey = msg._meta.memoryKey;
let history = flow.get(memoryKey) || [];
history = Array.isArray(history) ? history : [];

history.push({ role: 'user', content: msg._meta.receivedText, ts: Date.now() });
history.push({ role: 'assistant', content: aiText, ts: Date.now() });
history = history.slice(-10);
flow.set(memoryKey, history);

msg.method = 'POST';
msg.url = 'http://evolution-api:8080/message/sendText/' + encodeURIComponent(msg._meta.instance);
msg.headers = {
  'Content-Type': 'application/json',
  apikey: env.get('EVOLUTION_API_KEY')
};
msg.payload = {
  number: msg._meta.number,
  text: aiText,
  delay: 1000,
  linkPreview: false
};

msg._debug_ai = {
  number: msg._meta.number,
  instance: msg._meta.instance,
  pergunta: msg._meta.receivedText,
  resposta: aiText,
  memoryKey: msg._meta.memoryKey,
  dedupeKey: msg._meta.dedupeKey,
  providerErrorDetected: providerError
};

return msg;

msg.statusCode = 200;
msg.payload = {
  ok: true,
  sent: true,
  evolution_response: msg.payload,
  debug: msg._debug_ai || {}
};
return msg;

const meta = msg._meta || {};
const memoryKey = meta.memoryKey;
if (memoryKey) {
  let history = flow.get(memoryKey) || [];
  history = Array.isArray(history) ? history : [];
  history.push({ role: 'user', content: meta.receivedText || '', ts: Date.now() });
  history.push({ role: 'assistant', content: 'Recebi sua mensagem 👍 Estou finalizando um atendimento aqui e já te respondo melhor.', ts: Date.now() });
  history = history.slice(-10);
  flow.set(memoryKey, history);
}

msg.method = 'POST';
const instance = meta.instance || env.get('EVOLUTION_INSTANCE') || 'danielteste';
msg.url = 'http://evolution-api:8080/message/sendText/' + encodeURIComponent(instance);
msg.headers = {
  'Content-Type': 'application/json',
  apikey: env.get('EVOLUTION_API_KEY')
};
msg.payload = {
  number: meta.number,
  text: 'Recebi sua mensagem 👍\n\nEstou finalizando um atendimento aqui e já te respondo melhor.',
  delay: 1000,
  linkPreview: false
};
return msg;
